-- Table: portfolio_rows
-- Drop if re-running (optional)
-- DROP TABLE IF EXISTS portfolio_rows;

CREATE TABLE portfolio_rows (
  portfolio_id integer PRIMARY KEY,
  portfolio_strategy text NOT NULL,
  portfolio_name text NOT NULL,
  risk_profile text NOT NULL,
  benchmark text NOT NULL,
  description text NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now()
);

-- Enable RLS if needed (Supabase)
-- ALTER TABLE portfolio_rows ENABLE ROW LEVEL SECURITY;

INSERT INTO portfolio_rows (
  portfolio_id,
  portfolio_strategy,
  portfolio_name,
  risk_profile,
  benchmark,
  description,
  created_at
) VALUES
(1, 'ETF', 'Conservative', 'Low', 'Conservative', 'Designed to provide conservative growth potential the portfolio seeks to provide some capital appreciation potential and current income with a focus on low volatility. Invested in a majority of fixed income type investments with limited exposure to equities, this diversified portfolio may be appropriate for those investors who want to manage volatility and are somewhat sensitive to market fluctuations.', '2025-02-17 21:23:19.280031+00'),
(2, 'ETF', 'Moderate', 'Moderately Low', 'Conservative Balanced', 'Designed to provide moderate growth potential, the portfolio seeks the high total return over time consistent with a balance between capital growth and income. With a targeted equity weighted portfolio between equities and fixed income type investments, this diversified portfolio may be appropriate for those investors who want to manage volatility and are somewhat sensitive to market fluctuations.', '2025-02-17 21:24:26.160172+00'),
(3, 'ETF', 'Balanced', 'Moderate', 'Balanced', 'Designed to provide mid-cycle growth potential, this portfolio seeks to maximize total return potential with primary exposure to fixed-income type investments. In addition to equity-based investments for higher lost return potential, the portfolio includes fixed income exposure to help provide capital preservation over the long term and current income. This diversified portfolio may be appropriate for those investors who can accept a moderate level of volatility over a full market cycle.', '2025-02-17 21:37:25.856269+00'),
(4, 'ETF', 'Balanced with Growth', 'Moderately High', 'Balanced with Growth', 'Designed to provide long-term capital appreciation with strong growth potential, the portfolio is invested primarily in equities with limited exposure to fixed income. Although the core investments are equity-based for higher total return potential, the portfolio includes fixed income exposure to help provide capital preservation and income. This diversified portfolio may be appropriate for those investors who can accept a moderate level of volatility over a full market cycle.', '2025-02-17 21:38:09.373713+00'),
(5, 'ETF', 'Growth', 'High', 'Growth', 'Designed to provide long-term capital appreciation with strong growth potential, this portfolio strives to maximize total return potential with primary exposure to domestic equity investments and the ability to take advantage of opportunities in international markets. Invested primarily in equities with little exposure to fixed-income type investments, this diversified portfolio may be appropriate for those investors who can accept moderate to high level of volatility over a full market cycle.', '2025-02-17 21:39:13.412234+00'),
(6, 'Hybrid', 'Conservative', 'Low', 'Conservative', 'Designed to provide conservative growth potential the portfolio seeks to provide some capital appreciation potential and current income with a focus on low volatility. Invested in a majority of fixed income type investments with limited exposure to equities, this diversified portfolio may be appropriate for those investors who want to manage volatility and are somewhat sensitive to market fluctuations.', '2025-02-17 21:40:08.333222+00'),
(7, 'Hybrid', 'Moderate', 'Moderately Low', 'Conservative Balanced', 'Designed to provide moderate growth potential, the portfolio seeks the high total return over time consistent with a balance between capital growth and income. With a targeted equity weighted portfolio between equities and fixed income type investments, this diversified portfolio may be appropriate for those investors who want to manage volatility and are somewhat sensitive to market fluctuations.', '2025-02-17 21:40:48.452552+00'),
(8, 'Hybrid', 'Balanced', 'Moderate', 'Balanced', 'Designed to provide mid-cycle growth potential, this portfolio seeks to maximize total return potential with primary exposure to fixed-income type investments. In addition to equity-based investments for higher lost return potential, the portfolio includes fixed income exposure to help provide capital preservation over the long term and current income. This diversified portfolio may be appropriate for those investors who can accept a moderate level of volatility over a full market cycle.', '2025-02-17 21:41:03.132714+00'),
(9, 'Hybrid', 'Balanced with Growth', 'Moderately High', 'Balanced with Growth', 'Designed to provide long-term capital appreciation with strong growth potential, the portfolio is invested primarily in equities with limited exposure to fixed income. Although the core investments are equity-based for higher total return potential, the portfolio includes fixed income exposure to help provide capital preservation and income. This diversified portfolio may be appropriate for those investors who can accept a moderate level of volatility over a full market cycle.', '2025-02-17 21:41:42.337857+00'),
(10, 'Hybrid', 'Growth', 'High', 'Growth', 'Designed to provide long-term capital appreciation with strong growth potential, this portfolio strives to maximize total return potential with primary exposure to domestic equity investments and the ability to take advantage of opportunities in international markets. Invested primarily in equities with little exposure to fixed-income type investments, this diversified portfolio may be appropriate for those investors who can accept moderate to high level of volatility over a full market cycle.', '2025-02-17 21:42:13.133718+00'),
(11, 'Foundation', 'Conservative', 'Low', 'Conservative', 'Designed to provide conservative growth potential the portfolio seeks to provide some capital appreciation potential and current income with a focus on low volatility. Invested in a majority of fixed income type investments with limited exposure to equities, this diversified portfolio may be appropriate for those investors who want to manage volatility and are somewhat sensitive to market fluctuations.', '2025-02-17 21:43:02.222231+00'),
(12, 'Foundation', 'Moderate', 'Moderately Low', 'Conservative Balanced', 'Designed to provide moderate growth potential, the portfolio seeks the high total return over time consistent with a balance between capital growth and income. With a targeted equity weighted portfolio between equities and fixed income type investments, this diversified portfolio may be appropriate for those investors who want to manage volatility and are somewhat sensitive to market fluctuations.', '2025-02-17 21:43:20.123456+00'),
(13, 'Foundation', 'Balanced', 'Moderate', 'Balanced', 'Designed to provide mid-cycle growth potential, this portfolio seeks to maximize total return potential with primary exposure to fixed-income type investments. In addition to equity-based investments for higher lost return potential, the portfolio includes fixed income exposure to help provide capital preservation over the long term and current income. This diversified portfolio may be appropriate for those investors who can accept a moderate level of volatility over a full market cycle.', '2025-02-17 21:43:45.333341+00'),
(14, 'Foundation', 'Balanced with Growth', 'Moderately High', 'Balanced with Growth', 'Designed to provide long-term capital appreciation with strong growth potential, the portfolio is invested primarily in equities with limited exposure to fixed income. Although the core investments are equity-based for higher total return potential, the portfolio includes fixed income exposure to help provide capital preservation and income. This diversified portfolio may be appropriate for those investors who can accept a moderate level of volatility over a full market cycle.', '2025-02-17 21:44:06.123123+00'),
(15, 'Foundation', 'Growth', 'High', 'Growth', 'Designed to provide long-term capital appreciation with strong growth potential, this portfolio strives to maximize total return potential with primary exposure to domestic equity investments and the ability to take advantage of opportunities in international markets. Invested primarily in equities with little exposure to fixed-income type investments, this diversified portfolio may be appropriate for those investors who can accept moderate to high level of volatility over a full market cycle.', '2025-02-17 21:44:21.123123+00'),
(16, 'Equity', 'Income', 'High', 'S&P 500', 'The Equity Income portfolio aims to provide steady income by combining appreciation in prices with growing dividends, while managing risk and maintaining balance to the riskier sectors of the market. With a long-term approach to stock selection, focusing on sectors in their respective areas with an ability to consistently grow dividends over time. Emphasis is placed on the combination of stocks complementing each other toward the overall goals of the portfolio in terms of risk, income, and growth.', '2025-02-17 21:45:07.564531+00'),
(17, 'Equity', 'Growth', 'High', 'S&P 500', 'The Equity Growth portfolio seeks to provide long-term returns through a balanced approach to growth. This portfolio combines a multicap transition approach with bottom-up stock selection to deliver a diversified, large-cap, growth-oriented equity portfolio solution. Emphasis is placed on the combination of stocks complementing each other toward the overall goals of the portfolio in terms of risk, income, and growth.', '2025-02-17 21:45:43.715183+00'),
(18, 'Equity', 'Growth & Income', 'High', 'S&P 500', 'The Equity Growth & Income portfolio seeks to provide long-term returns by combining the benefits of dividend income and capital appreciation within a diversified equity portfolio. The strategy focuses on high quality companies with durable competitive advantages, strong balance sheets, and the ability to grow earnings and shareholder returns over time. Using a combination of top-down market perspective and bottom-up stock selection, the portfolio managers identify leading companies that are capable of delivering sustainable earnings growth and maintaining a commitment to returning capital to shareholders through dividends. The portfolio is constructed with growth, income and diversification in mind, emphasizing individual holdings complement each other in overall risk/return terms for the overall goals of risk, income, and growth.', '2025-02-17 21:46:33.434343+00'),
(19, 'Fixed Income', 'Total Return', 'Low', 'Bloomberg U.S. Aggregate Bond', 'Designed to provide a stream of income from a selection of income producing investments. With 100% of the portfolio allocated to diversified fixed income, the portfolio is structured to provide capital preservation. This portfolio may be appropriate for those investors who want to carefully manage quality and are sensitive to short term losses and the effects of market fluctuations.', '2025-02-17 21:47:37.575454+00');
